window.bookSummaryJSON = "<p>Christmas week can’t get any worse for Jules Jilliland.</p> <p>Dumped by her boyfriend, rear-ended on the freeway, and fired from her job, she finds herself stuck in an elevator with a handsome stranger.</p> <p>When their packages are accidentally swapped, will it end up being a misfortunate accident that suddenly brightens her holidays?</p> <p>(Previously released in the 2019 <i>All Wrapped Up Christmas Anthology</i>)</p>"; 
